import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  Grid,
  Paper,
  Card,
  CardContent,
  CardHeader,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  IconButton,
  Alert,
  Chip,
  List,
  ListItem,
  ListItemText,
  ListItemSecondary,
  Divider,
  Tabs,
  Tab,
} from '@mui/material';
import {
  People as PeopleIcon,
  LocalHospital as HospitalIcon,
  Event as EventIcon,
  AttachMoney as MoneyIcon,
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  Close as CloseIcon,
  AccessTime as TimeIcon,
  Description as DescriptionIcon,
  CheckCircle as CheckCircleIcon,
  Cancel as CancelIcon,
  Check as ApproveIcon,
  Close as RejectIcon,
  Assessment as ReportIcon,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { format } from 'date-fns';

const Dashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalPatients: 0,
    totalDoctors: 0,
    totalAppointments: 0,
    totalRevenue: 0,
    pendingApprovals: 0,
  });
  const [recentAppointments, setRecentAppointments] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [openDepartmentDialog, setOpenDepartmentDialog] = useState(false);
  const [selectedDepartment, setSelectedDepartment] = useState(null);
  const [departmentForm, setDepartmentForm] = useState({
    name: '',
    description: '',
    headDoctor: '',
  });
  const [pendingDoctors, setPendingDoctors] = useState([]);
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);
  const [rejectReason, setRejectReason] = useState('');
  const [recentActivity, setRecentActivity] = useState([]);
  const [activeTab, setActiveTab] = useState(0);

  useEffect(() => {
    fetchDashboardData();
    fetchPendingDoctors();
    fetchRecentActivity();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [statsRes, appointmentsRes, departmentsRes] = await Promise.all([
        axios.get('http://localhost:5000/api/admin/stats', {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        }),
        axios.get('http://localhost:5000/api/admin/recent-appointments', {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        }),
        axios.get('http://localhost:5000/api/departments', {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        }),
      ]);

      setStats(statsRes.data);
      setRecentAppointments(appointmentsRes.data);
      setDepartments(departmentsRes.data);
    } catch (err) {
      setError('Failed to fetch dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const fetchPendingDoctors = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/admin/pending-doctors');
      setPendingDoctors(response.data);
    } catch (error) {
      console.error('Error fetching pending doctors:', error);
    }
  };

  const fetchRecentActivity = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/admin/recent-activity');
      setRecentActivity(response.data);
    } catch (error) {
      setError('Failed to fetch recent activity');
    }
  };

  const handleOpenDepartmentDialog = (department = null) => {
    if (department) {
      setSelectedDepartment(department);
      setDepartmentForm({
        name: department.name,
        description: department.description,
        headDoctor: department.headDoctor?._id || '',
      });
    } else {
      setSelectedDepartment(null);
      setDepartmentForm({
        name: '',
        description: '',
        headDoctor: '',
      });
    }
    setOpenDepartmentDialog(true);
  };

  const handleCloseDepartmentDialog = () => {
    setOpenDepartmentDialog(false);
    setSelectedDepartment(null);
    setDepartmentForm({
      name: '',
      description: '',
      headDoctor: '',
    });
  };

  const handleDepartmentChange = (e) => {
    const { name, value } = e.target;
    setDepartmentForm(prev => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleDepartmentSubmit = async (e) => {
    e.preventDefault();
    try {
      if (selectedDepartment) {
        await axios.put(
          `http://localhost:5000/api/departments/${selectedDepartment._id}`,
          departmentForm,
          { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
        );
        setSuccess('Department updated successfully');
      } else {
        await axios.post(
          'http://localhost:5000/api/departments',
          departmentForm,
          { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } }
        );
        setSuccess('Department created successfully');
      }
      handleCloseDepartmentDialog();
      fetchDashboardData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save department');
    }
  };

  const handleDeleteDepartment = async (departmentId) => {
    if (window.confirm('Are you sure you want to delete this department?')) {
      try {
        await axios.delete(`http://localhost:5000/api/departments/${departmentId}`, {
          headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        });
        setSuccess('Department deleted successfully');
        fetchDashboardData();
      } catch (err) {
        setError('Failed to delete department');
      }
    }
  };

  const handleApproveDoctor = async (doctorId) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/approve-doctor/${doctorId}`);
      setSuccess('Doctor approved successfully');
      fetchPendingDoctors();
      fetchDashboardData();
    } catch (error) {
      setError('Failed to approve doctor');
    }
  };

  const handleRejectDoctor = async (doctorId) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/reject-doctor/${doctorId}`, {
        reason: rejectReason,
      });
      setOpenDialog(false);
      setRejectReason('');
      fetchPendingDoctors();
      fetchDashboardData();
    } catch (error) {
      console.error('Error rejecting doctor:', error);
    }
  };

  const StatCard = ({ icon: Icon, title, value, color }) => (
    <Card>
      <CardContent>
        <Box display="flex" alignItems="center" mb={2}>
          <Icon sx={{ fontSize: 40, color: color }} />
          <Typography variant="h6" ml={2} color="text.secondary">
            {title}
          </Typography>
        </Box>
        <Typography variant="h4" component="div">
          {value}
        </Typography>
      </CardContent>
    </Card>
  );

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={4}>
        <Box>
          <Typography variant="h4" component="h1" gutterBottom>
            Admin Dashboard
          </Typography>
          <Typography variant="subtitle1" color="text.secondary">
            {format(new Date(), 'EEEE, MMMM d, yyyy')}
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<ReportIcon />}
          color="primary"
        >
          Generate Reports
        </Button>
      </Box>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <Grid container spacing={3} mb={4}>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={HospitalIcon}
            title="Total Doctors"
            value={stats.totalDoctors}
            color="#1976d2"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={PeopleIcon}
            title="Total Patients"
            value={stats.totalPatients}
            color="#2e7d32"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={EventIcon}
            title="Appointments"
            value={stats.totalAppointments}
            color="#ed6c02"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            icon={PeopleIcon}
            title="Pending Doctors"
            value={stats.pendingApprovals}
            color="#d32f2f"
          />
        </Grid>
      </Grid>

      <Grid container spacing={3}>
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Doctor Approval Requests
            </Typography>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Name</TableCell>
                    <TableCell>Specialization</TableCell>
                    <TableCell>Experience</TableCell>
                    <TableCell>License No.</TableCell>
                    <TableCell>Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {pendingDoctors.map((doctor) => (
                    <TableRow key={doctor._id}>
                      <TableCell>{doctor.name}</TableCell>
                      <TableCell>
                        <Chip label={doctor.specialization} color="primary" size="small" />
                      </TableCell>
                      <TableCell>{doctor.experience} years</TableCell>
                      <TableCell>{doctor.license.number}</TableCell>
                      <TableCell>
                        <IconButton
                          color="success"
                          onClick={() => handleApproveDoctor(doctor._id)}
                          title="Approve"
                        >
                          <ApproveIcon />
                        </IconButton>
                        <IconButton
                          color="error"
                          onClick={() => {
                            setSelectedDoctor(doctor);
                            setOpenDialog(true);
                          }}
                          title="Reject"
                        >
                          <RejectIcon />
                        </IconButton>
                      </TableCell>
                    </TableRow>
                  ))}
                  {pendingDoctors.length === 0 && (
                    <TableRow>
                      <TableCell colSpan={5} align="center">
                        No pending doctor approvals
                      </TableCell>
                    </TableRow>
                  )}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        </Grid>

        <Grid item xs={12} md={4}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Recent Activity
            </Typography>
            <List>
              {recentActivity.map((activity) => (
                <React.Fragment key={activity._id}>
                  <ListItem>
                    <ListItemText
                      primary={activity.description}
                      secondary={format(new Date(activity.timestamp), 'MMM d, yyyy h:mm a')}
                    />
                    <Chip
                      label={activity.type}
                      color={
                        activity.type === 'approval' ? 'success' :
                        activity.type === 'rejection' ? 'error' : 'default'
                      }
                      size="small"
                    />
                  </ListItem>
                  <Divider />
                </React.Fragment>
              ))}
              {recentActivity.length === 0 && (
                <ListItem>
                  <ListItemText primary="No recent activity" />
                </ListItem>
              )}
            </List>
          </Paper>
        </Grid>
      </Grid>

      {/* Departments Management */}
      <Paper sx={{ p: 3, mt: 4 }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
          <Typography variant="h6">Departments</Typography>
          <Button
            variant="contained"
            startIcon={<AddIcon />}
            onClick={() => handleOpenDepartmentDialog()}
          >
            Add Department
          </Button>
        </Box>
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Description</TableCell>
                <TableCell>Head Doctor</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {departments.map((department) => (
                <TableRow key={department._id}>
                  <TableCell>{department.name}</TableCell>
                  <TableCell>{department.description}</TableCell>
                  <TableCell>
                    {department.headDoctor?.userId.name || 'Not assigned'}
                  </TableCell>
                  <TableCell>
                    <IconButton
                      size="small"
                      onClick={() => handleOpenDepartmentDialog(department)}
                    >
                      <EditIcon />
                    </IconButton>
                    <IconButton
                      size="small"
                      color="error"
                      onClick={() => handleDeleteDepartment(department._id)}
                    >
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      {/* Reject Doctor Dialog */}
      <Dialog
        open={openDialog}
        onClose={() => setOpenDialog(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>Reject Doctor Application</DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            margin="dense"
            label="Reason for Rejection"
            fullWidth
            multiline
            rows={4}
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenDialog(false)}>Cancel</Button>
          <Button
            onClick={() => handleRejectDoctor(selectedDoctor?._id)}
            color="error"
            variant="contained"
          >
            Reject
          </Button>
        </DialogActions>
      </Dialog>

      {/* Department Dialog */}
      <Dialog
        open={openDepartmentDialog}
        onClose={handleCloseDepartmentDialog}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Typography variant="h6">
              {selectedDepartment ? 'Edit Department' : 'Add Department'}
            </Typography>
            <IconButton onClick={handleCloseDepartmentDialog}>
              <CloseIcon />
            </IconButton>
          </Box>
        </DialogTitle>
        <DialogContent>
          <Box component="form" onSubmit={handleDepartmentSubmit} sx={{ mt: 2 }}>
            <Grid container spacing={3}>
              <Grid item xs={12}>
                <TextField
                  required
                  fullWidth
                  label="Department Name"
                  name="name"
                  value={departmentForm.name}
                  onChange={handleDepartmentChange}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  multiline
                  rows={3}
                  label="Description"
                  name="description"
                  value={departmentForm.description}
                  onChange={handleDepartmentChange}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth>
                  <InputLabel>Head Doctor</InputLabel>
                  <Select
                    name="headDoctor"
                    value={departmentForm.headDoctor}
                    onChange={handleDepartmentChange}
                    label="Head Doctor"
                  >
                    <MenuItem value="">Select Head Doctor</MenuItem>
                    {stats.doctors?.map((doctor) => (
                      <MenuItem key={doctor._id} value={doctor._id}>
                        {doctor.userId.name}
                      </MenuItem>
                    ))}
                  </Select>
                </FormControl>
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDepartmentDialog}>Cancel</Button>
          <Button
            variant="contained"
            onClick={handleDepartmentSubmit}
          >
            {selectedDepartment ? 'Update' : 'Create'}
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default Dashboard;
